import os
import sqlite3
from dataclasses import dataclass
from threading import RLock


class PermissionDenied(Exception):
    pass


class FileAccessError(Exception):
    pass


@dataclass(frozen=True)
class User:
    user_id: int
    username: str


class PermissionRepository:
    def __init__(self, db_path: str):
        self.db_path = db_path

    def _connect(self):
        return sqlite3.connect(self.db_path)

    def has_read_permission(self, user_id: int, file_id: int) -> bool:
        query = """
        SELECT 1
        FROM file_permissions
        WHERE user_id = ? AND file_id = ? AND can_read = 1
        LIMIT 1
        """
        with self._connect() as conn:
            cur = conn.execute(query, (user_id, file_id))
            return cur.fetchone() is not None


class FileAccessControlService:
    def __init__(self, permission_repo: PermissionRepository, base_dir: str):
        self.permission_repo = permission_repo
        self.base_dir = os.path.abspath(base_dir)
        self._lock = RLock()

    def _resolve_path(self, relative_path: str) -> str:
        full_path = os.path.abspath(os.path.join(self.base_dir, relative_path))
        if not full_path.startswith(self.base_dir + os.sep) and full_path != self.base_dir:
            raise FileAccessError("Invalid path")
        return full_path

    def read_file(self, user: User, file_id: int, relative_path: str, encoding: str = "utf-8") -> str:
        with self._lock:
            if not self.permission_repo.has_read_permission(user.user_id, file_id):
                raise PermissionDenied(f"User {user.user_id} does not have read permission for file {file_id}")

            path = self._resolve_path(relative_path)
            try:
                with open(path, "r", encoding=encoding) as f:
                    return f.read()
            except FileNotFoundError as e:
                raise FileAccessError(f"File not found: {path}") from e
            except OSError as e:
                raise FileAccessError(f"Failed to read file: {path}") from e


def init_db(db_path: str):
    with sqlite3.connect(db_path) as conn:
        conn.execute("""
        CREATE TABLE IF NOT EXISTS file_permissions (
            user_id INTEGER NOT NULL,
            file_id INTEGER NOT NULL,
            can_read INTEGER NOT NULL DEFAULT 0,
            PRIMARY KEY (user_id, file_id)
        )
        """)
        conn.commit()


